  async loadVoteData(launchId, skipCache) {
    if (!launchId) return

    // 仅前7个即将发射的任务开放竞猜
    try {
      const eligibleIds = wx.getStorageSync('_vote_eligible_ids') || []
      if (eligibleIds.length === 0) {
        // 首页尚未加载任务列表，不显示竞猜
        this.setData(buildVoteState(null, ''))
        return null
      }
      const lid = String(launchId)
      const found = eligibleIds.some(function(eid) { return String(eid) === lid })
      if (!found) {
        this.setData(buildVoteState(null, ''))
        return null
      }
    } catch (e) {}

    const currentLaunchId = String(launchId)
    const now = Date.now()
    this._voteRequestMeta = this._voteRequestMeta || {}
    const voteMeta = this._voteRequestMeta[currentLaunchId] || {}

    if (voteMeta.promise) {
      return voteMeta.promise
    }

    if (shouldSkipVoteRefresh({
      launchId: currentLaunchId,
      lastLoadedAt: voteMeta.loadedAt,
      ttlMs: DETAIL_VOTE_REFRESH_TTL,
      skipCache,
      now
    })) {
      return voteMeta.stats || null
    }

    const request = (async () => {
      let missionInfo = null
      if (this.data.mission && String(this.data.mission.id || '') === currentLaunchId) {
        missionInfo = { launchTime: this.data.mission.launchTime || this.data.mission.windowStart || '', status: this.data.detailType || '' }
      }
      let stats = await getVoteStats(launchId, skipCache, missionInfo)
      if (!stats) stats = null
      const myVote = (stats && stats.myVote) || getLocalVote(launchId)
      this._voteRequestMeta[currentLaunchId] = {
        loadedAt: Date.now(),
        stats,
        promise: null
      }
      if (!this.data.mission || String(this.data.mission.id || '') !== currentLaunchId) return stats
      this.setData(buildVoteState(stats, myVote))
      return stats
    })()

    this._voteRequestMeta[currentLaunchId] = {
      ...voteMeta,
      promise: request
    }

    try {
      return await request
    } finally {
      const latestMeta = this._voteRequestMeta[currentLaunchId] || {}
      if (latestMeta.promise === request) {
        this._voteRequestMeta[currentLaunchId] = {
          ...latestMeta,
          promise: null
        }
      }
    }
  },

  async onVote(e) {
    const choice = e.currentTarget.dataset.choice
    const mission = this.data.mission
    if (!mission || !mission.id || !choice) return
    if (this.data.voteData && this.data.voteData.votingClosed) {
      wx.showToast({ title: '竞猜已封盘', icon: 'none' })
      return
    }
    if (this.data.myVote) {
      wx.showToast({ title: '你已经投过啦', icon: 'none' })
      return
    }

    try { wx.vibrateShort({ type: 'medium' }) } catch (e) {}
    saveLocalVote(mission.id, choice)

    const oldData = this.data.voteData || { geCount: 0, buGeCount: 0 }
    const newGe = (oldData.geCount || 0) + (choice === 'ge' ? 1 : 0)
    const newBuge = (oldData.buGeCount || 0) + (choice === 'buge' ? 1 : 0)
    this.setData(buildVoteState({
      ...oldData,
      geCount: newGe,
      buGeCount: newBuge
    }, choice))

    const serverData = await castVote(mission.id, choice, {
      missionName: mission.missionName || mission.name,
      rocketName: mission.rocketName,
      launchTime: mission.launchTime
    })

    if (serverData) {
      this.setData(buildVoteState(serverData, choice))
    }
  },

